form:Form.form:Scripts:
		function ToList()
{                
	if (parseInt(Ctrl("iter-size").GetXValue(),10)<=400)

	{
		if (Ctrl('main').GetMode()=="EDIT")
	   {		
	    	if (validarDiasPedidos())
	    	{ 
	    	  Ctrl("LISTA").DoEvent("showList");
	    	}	
	   } 
	   else 
	   Ctrl("LISTA").DoEvent("showList");	
	}

	else
		alert("Demasiados registros para ser mostrados en una lista.");
}

function hab_tipofliar(myThis)
{           
	var codLicFliar = Ctrl('codLicFliar').GetXValue().toString();
	if(codLicFliar!='')
	{ 
		//si el valor que llega es la licencia - valido que sea de tipo familiar enfermo segun el parametro
		if(myThis.ID()=='oi_licencia')
		{
			if(Ctrl("oi_licencia").GetXValue() != '')
			{             
				var cod_lic =  Ctrl("oi_licencia").GetCValue().replace(" ","").split("-");
				var c_lic = cod_lic[0];  			


				//if(codLicFliar.indexOf(c_lic) != -1)
				if(codLicFliar.toString() == c_lic.toString())
				{	
					Ctrl('oi_familiar_per').SetEnabled(true);
				}        	
				else
				{    
					Ctrl('oi_familiar_per').SetXValue("");
					Ctrl('oi_familiar_per').SetEnabled(false);			
				}
			}		
		}	
	}	
	//en onchange del control de licencias tiene que llamar al calcular dias despues de habilitar al combo de tipo de familiar
	calcular_dias(myThis); 	
}

function validar_f_fin(myThis)
{	                            
	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

	if (myThis.GetXValue() < Ctrl('f_inicio').GetXValue())
	{
		myThis.SetError("La fecha de Fin debe ser posterior o igual a la fecha de Inicio");
		return false;
	}
	else 
		return true;
}

function calcular_dias(myThis)
{       
	//sugiero año corresp. si lo llamo desde f_inicio	
	if(((myThis.ID()=='f_inicio') || (myThis.ID()=='oi_licencia') || (myThis.ID()=='oi_familiar_per')) && (Ctrl('f_inicio').GetCValue()!=""))
	{
		sugerirAnoCorresp();
		calcularSaldo();
	}

	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

 	if (Ctrl('f_fin').GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
 	{ 		
 		if (Ctrl('f_fin').GetXValue() >= Ctrl('f_inicio').GetXValue())
 		{
 			Ctrl('e_cant_dias').SetTypedValue(DiffDays(Ctrl('f_fin').TypedValue(), Ctrl('f_inicio').TypedValue()) + 1);
 		} 
 		else Ctrl('e_cant_dias').SetXValue("");
 	}
 	else Ctrl('e_cant_dias').SetXValue("");     	

 	return true;
}

function calcular_f_fin(myThis)
{
	if (isInteger(Ctrl('e_anio_corresp').GetXValue()))
	{
		if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

		if (myThis.GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
		{
			Ctrl('f_fin').SetTypedValue(AddDays(Ctrl('f_inicio').TypedValue(), Ctrl('e_cant_dias').TypedValue()-1));
		}
		else Ctrl('f_fin').SetXValue("");
		return true;
	} 
	else
		return false;
}

function EDIT_ACCEPT(myThis)
{	   
	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;
	if (Ctrl("main").GetSavedDoc("OBJ")?false:true) return true;

	var MyLIQPER=new NomadXML(Ctrl("main").GetSavedDoc("OBJ"));
	var t;
	var f_inicio, f_fin;

	if (!CtrlExists("LIST"))
		for (var cur = MyLIQPER.FirstChild(); cur!=null; cur=cur.Next())
		{
			if (cur.GetAttr("nmd-status").substr(0, 3) == "~d,") continue;
			if (cur.GetAttr("nmd-status").substr(0, 3) == "~x,") continue;

			if (CtrlExists("e_id") && (cur.GetAttr("id")==Ctrl("e_id").GetXValue())) continue;

			f_inicio=cur.GetAttrDateTime("f_inicio");
			if (cur.GetAttr("f_interrupcion") != "") f_fin=cur.GetAttrDateTime("f_interrupcion");
			                                    else f_fin=cur.GetAttrDateTime("f_fin");

			if (Ctrl("f_inicio").TypedValue() > f_fin) continue;
			if (Ctrl("f_fin").TypedValue() < f_inicio) continue;

			myThis.SetError("La licencia actual se solapa con otra licencia del " + formatDate(f_inicio, "dd/mm/yyyy") + " al " + formatDate(f_fin, "dd/mm/yyyy"));
			return false;
		}             

	return true;
}

function EnableControl()
{              
	var myOBJ=Ctrl("main").GetLastDoc("OBJ");
	if (myOBJ!=null) Ctrl("main").SaveDoc(myOBJ, "OBJ");

 	if (CtrlExists("l_bloqueada"))
 	{
		if (Ctrl("l_bloqueada").GetXValue()=="1")
		{                   
			CtrlEnabled("oi_licencia",false);
			CtrlEnabled("f_inicio",false);
			CtrlEnabled("f_fin",false);
			CtrlEnabled("e_cant_dias",false);
			CtrlEnabled("e_anio_corresp",false);
			CtrlEnabled("e_cant_dias",false);
			CtrlEnabled("f_interrupcion",false);
			CtrlEnabled("DELETE",false);        
			CtrlEnabled("INTERRUPT",true);
		} else
			CtrlEnabled("INTERRUPT",false);
	} else
 	if (CtrlExists("LIST"))
 	{      
 		LIST_onClick(Ctrl("LIST"));
	}

	//cargar saldo en modo registro
	if(Ctrl("main").GetMode()=='EDIT')
	{
		calcularSaldo();
	//validar si se puede editar 	 
		ValidarModif();
	}  

	if(Ctrl("main").GetMode()=='NEW')
	{
		Ctrl('oi_familiar_per').SetEnabled(false);	
	}

	if(Ctrl("main").GetMode()=='EDIT' || Ctrl("main").GetMode()=='NEW' || Ctrl("main").GetMode()=='SHOW')
    {
		var v_param;

		//Recupero el codigo de la licencia por familiar en el parametro
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");	

		//Si existe el parametro - el cliente controla
		if (typeof (param.d_valor) != "undefined")
		{
			v_param = param.d_valor.toString();		
		}
		else
		{
			v_param = "";
		} 	

		Ctrl('codLicFliar').SetXValue(v_param);
    }


}

function LIST_onClick(myThis)
{                                         
	if (myThis.GetSelectAttrValue("l_bloqueada")=="1")
	{
		CtrlEnabled("DELETE",false);   
		CtrlEnabled("INTERRUPT",true);
	} else
	{
		CtrlEnabled("DELETE",true);   
		CtrlEnabled("INTERRUPT",false);
	}
}

function sugerirAnoCorresp()
{                                
	var fecha = Ctrl("f_inicio").TypedValue().getFullYear()
	Ctrl('e_anio_corresp').SetTypedValue(fecha);
	Ctrl('e_cant_dias').SetXValue("");
	Ctrl('f_fin').SetXValue("");
}

