	//alert('e_max_dias_lic: ' + Ctrl('e_max_dias_lic').GetXValue());
	//alert('e_saldo: ' + Ctrl('e_saldo').GetXValue());            
	//alert('e_cant_dias: ' + Ctrl('e_cant_dias').GetXValue());   

	if (Ctrl("main").GetMode()=="LIST" || Ctrl("main").GetMode()=="LIST_EDIT" || Ctrl("main").GetMode()=="SHOW" || Ctrl('vm').GetXValue()==1) return true;

	//Si tiene tope anual y tiene licencias
	/*if((Ctrl('e_max_dias_anio').GetXValue()!='NULL') && (Ctrl('e_saldo').GetXValue() !=''))
	{

		if(Ctrl('e_cant_dias').TypedValue() > Ctrl('e_saldo').TypedValue())
		{
			//El saldo es insuficiente
			//preguntar si quiere aprobar de todos modos
			var r=confirm("La cantidad de dias de licencia indicados supera el tope anual establecido. Desea continuar de todos modos?");

			if(r!=true)    //si es true debe validar los dias pedidos en la licencia actual
				return false;
		}

		//si le queda saldo continua validando los dias			
	}

	if(Ctrl('e_max_dias_lic').GetXValue()!='NULL')
	{
		if(Ctrl('e_cant_dias').TypedValue() > str2number(Ctrl('e_max_dias_lic').GetXValue()))
		{
			//alert('dias invalidos');
			//preguntar si quiere aprobar de todos modos
			var r=confirm("La cantidad de dias indicados supera el límite permitido por licencia. Desea continuar de todos modos?");

			if(r==true)
				return true;
			else
				return false;
		}
		//else
		//	alert('dias validos');	
		return true;
	}*/

	//Valida si supera el maximo permitido de la licencia
	if(Ctrl('e_max_dias_lic').GetXValue()!='')
	{
		if(Ctrl('e_cant_dias').TypedValue() > str2number(Ctrl('e_max_dias_lic').GetXValue()))
		{
			if(Ctrl('l_max_dias_lic').GetXValue()=="1")
			{
				return confirm("La cantidad de días indicados supera el límite permitido por licencia.\n¿Confirma licencia?");				
			}
			else
			{
				alert("La cantidad de días indicados supera el límite permitido por licencia");
			 	return false;
			}
		}
	} 

	//Si tiene tope anual y tiene licencias
	if((Ctrl('e_max_dias_anio').GetXValue()!='') && (Ctrl('e_saldo').GetXValue() !=''))
	{


		if(Ctrl('e_cant_dias').TypedValue() > Ctrl('e_saldo').TypedValue())
		{
			if(Ctrl('l_max_dias_anio').GetXValue()=="1" )
			{
				return confirm("La cantidad de días de licencia indicados supera el tope anual establecido.\n¿Confirma licencia?");				
			}
			else
			{
				alert("La cantidad de días de licencia indicados supera el tope anual establecido.");
				return false;
			}
		}		
	}  


	if((Ctrl('e_min_meses_antig').GetXValue()!='') && (Ctrl('e_min_meses_antig').GetXValue()>calcularAntiguedad()))
	{
		if(Ctrl('l_min_meses_antig').GetXValue()==1)
